# tools/registry.py
"""Central registry that maps tool names to callables.
Import side effects (model loads, DB connections) are deferred to first call."""
from __future__ import annotations
from typing import Callable, Any

_REGISTRY: dict[str, Callable[..., Any]] = {}

def register(name: str):
    """Decorator: @register('search') marks a function as a tool."""
    def decorator(fn: Callable[..., Any]):
        _REGISTRY[name] = fn
        return fn
    return decorator

def get_tool(name: str) -> Callable[..., Any]:
    if name not in _REGISTRY:
        raise KeyError(f"Unknown tool: {name!r}. Available: {list_tools()}")
    return _REGISTRY[name]

def list_tools() -> list[str]:
    return sorted(_REGISTRY)


