    # Force registration by importing the modules
    import tools.search    # noqa: F401
    import tools.calculator  # noqa: F401

    print("Available tools:", list_tools())
    print(dispatch_tool("calculate", {"expression": "3 * (4 + 5)"}))  # 27.0
    print(dispatch_tool("search", {"query": "agentic AI", "max_results": 2}))

