# Lazy import pattern for cold-start-sensitive environments
def get_embedding_model():
    """Load the embedding model only when first needed, not at startup."""
    # This import triggers torch and transformers loading — ~2s on CPU
    from sentence_transformers import SentenceTransformer  # noqa: PLC0415
    return SentenceTransformer("all-MiniLM-L6-v2")

_embedding_model = None

def embed(text: str) -> list[float]:
    global _embedding_model
    if _embedding_model is None:
        _embedding_model = get_embedding_model()
    return _embedding_model.encode(text).tolist()

# Graceful handling of optional dependency
try:
    import numpy as np
    HAS_NUMPY = True
except ImportError:
    HAS_NUMPY = False

def vectorize(texts: list[str]) -> list[list[float]] | None:
    if not HAS_NUMPY:
        return None   # caller checks and uses a fallback
    return [np.random.rand(768).tolist() for _ in texts]  # placeholder
